              onChange={e => setInvoiceInfo({...invoiceInfo, terms: e.target.value})}
              rows={4}
              className="w-full border border-border-light p-2.5 text-sm rounded-sm focus:outline-none focus:border-gold"
            />
          </div>
        </div>
      </div>

    </div>
  );
}

